import edu.stanford.nlp.ling.CoreAnnotations;
import edu.stanford.nlp.ling.CoreLabel;
import edu.stanford.nlp.pipeline.Annotation;
import edu.stanford.nlp.pipeline.StanfordCoreNLP;
import edu.stanford.nlp.util.CoreMap;

// Initialize Stanford CoreNLP pipeline
StanfordCoreNLP pipeline = new StanfordCoreNLP();

// Example sentence
String sentence = 'The quick brown fox jumps over the lazy dog.';

// Create annotation
Annotation annotation = new Annotation(sentence);

// Run pipeline
pipeline.annotate(annotation);

// Get POS tags
for (CoreMap sentenceMap : annotation.get(CoreAnnotations.SentencesAnnotation.class)) {
 for (CoreLabel token : sentenceMap.get(CoreAnnotations.TokensAnnotation.class)) {
 String posTag = token.get(CoreAnnotations.PartOfSpeechAnnotation.class);
 System.out.println('Token: ' + token.word() + ', POS Tag: ' + posTag);
 }
}
